// Parse Request v2.1 — extract fields from incoming message/webhook
// v2.1: articleUrl optional (Pressfeed use case), targetLength support
const items = $input.all();
const inputData = items[0].json;

const messageText = inputData.message?.text || inputData.text || '';

function extractField(text, pattern) {
  const match = text.match(pattern);
  return match ? match[1].trim() : '';
}

// Extract fields - try webhook JSON first, then message text
let person = inputData.person || extractField(messageText, /(?:PERSON:|СПИКЕР:)\s*(.*)$/im) || '';
let articleUrl = inputData.articleUrl || extractField(messageText, /(?:LINK:|ССЫЛКА:|URL:)\s*(.*)$/im) || '';
let question = inputData.question || extractField(messageText, /(?:QUESTION:|ВОПРОС:)\s*(.*)$/im) || '';

// targetLength from webhook or message (v2.1: comment length selector)
let targetLength = inputData.targetLength || extractField(messageText, /(?:ДЛИНА:|LENGTH:|CHARACTERS?:)\s*(.*)$/im) || '';
if (!targetLength.match(/^\d+-\d+$/)) {
  targetLength = '1500-2000';
}

// Clean URL
let cleanUrl = '';
try {
  if (articleUrl && articleUrl.startsWith('http')) {
    cleanUrl = new URL(articleUrl).href;
  }
} catch (e) {
  cleanUrl = '';
}

// Normalize person aliases
const personLower = person.toLowerCase();
const personAliases = {
  'maria': 'maria_arkhangelskaya', 'мария': 'maria_arkhangelskaya',
  'masha': 'maria_arkhangelskaya', 'маша': 'maria_arkhangelskaya',
  'ilya': 'ilya_morozov', 'илья': 'ilya_morozov',
  'morozov': 'ilya_morozov', 'морозов': 'ilya_morozov',
};
const requestedProfileId = personAliases[personLower] || person || 'maria_arkhangelskaya';

const chatId = inputData.message?.chat?.id || inputData.chatId || '';
const userId = inputData.message?.from?.id || inputData.userId || '';
const source = inputData.source || 'telegram';
const callbackUrl = inputData.callbackUrl || '';
const jobId = inputData.jobId || '';

// Validation: only question is required. articleUrl is optional (v2.1).
const missingFields = [];
if (!question) missingFields.push('QUESTION/вопрос');

return [{
  json: {
    requestedProfileId,
    articleUrl: cleanUrl,
    question,
    targetLength,
    chatId: String(chatId),
    userId: String(userId),
    source,
    callbackUrl,
    jobId,
    rawPerson: person,
    isValid: missingFields.length === 0,
    missingFields,
  }
}];

function parseGithubFile(payload) {
  if (!payload || typeof payload !== 'object') return null;
  if (payload.profile_id) return payload;
  if (typeof payload.content === 'string') {
    try {
      const decoded = Buffer.from(payload.content, 'base64').toString('utf8');
      return JSON.parse(decoded);
    } catch (_) {
      return null;
    }
  }
  return null;
}

const upstream = $('Parse Request').first().json;
const payload = $input.first().json || {};
const parsed = parseGithubFile(payload);

const requestedProfile = parsed && typeof parsed === 'object' ? parsed : null;
const requestedProfileValid = Boolean(requestedProfile && requestedProfile.active === true);

return [{
  json: {
    ...upstream,
    requestedProfile,
    requestedProfileValid,
    profileRequested: upstream.requestedProfileId || upstream.profileId || 'maria_arkhangelskaya',
    profileResolutionHint: requestedProfileValid ? 'requested_active' : 'fallback_default',
    profileFetchError: payload.error || null,
  },
}];

