const inputData = $input.first().json || {};
const rawOutput = String(inputData.output || inputData.text || '').trim();

function unwrapFences(text) {
  return String(text || '').replace(/^```[a-zA-Z]*\n?/,'').replace(/\n?```$/,'').trim();
}

let comment = '';

// Match ## or ### комментарий section using Unicode to avoid encoding corruption
const sectionMatch = rawOutput.match(/#{2,3}\s*комментарий\s*[\r\n]+([\s\S]*?)(?=\n#{2,3}|$)/i);
if (sectionMatch && sectionMatch[1]) {
  comment = sectionMatch[1].trim();
}

// Fallback: plain комментарий label without markdown heading
if (!comment) {
  const plainMatch = rawOutput.match(/комментарий[:\s]*[\r\n]+([\s\S]*?)(?=\n#{1,3}|$)/i);
  if (plainMatch && plainMatch[1] && plainMatch[1].trim().length > 200) {
    comment = plainMatch[1].trim();
  }
}

// Fallback: extract everything after any комментарий occurrence
if (!comment) {
  const broadMatch = rawOutput.match(/комментарий[\s\S]{0,5}\n([\s\S]+)/i);
  if (broadMatch && broadMatch[1] && broadMatch[1].trim().length > 200) {
    comment = broadMatch[1].trim();
    const checkIdx = comment.search(/\n#{1,3}/i);
    if (checkIdx > 0) comment = comment.substring(0, checkIdx).trim();
  }
}

// Fallback: find largest quoted block («» or "")
if (!comment) {
  const quoteMatch = rawOutput.match(/[«"][\s\S]{280,}[»"]/);
  if (quoteMatch) comment = quoteMatch[0].trim();
}

// Final fallback: use full output
if (!comment) {
  comment = rawOutput;
}

comment = unwrapFences(comment);

if (!comment && rawOutput) {
  comment = unwrapFences(rawOutput);
}

return [{
  json: {
    ...inputData,
    fullOutput: rawOutput,
    comment,
    charCount: String(comment || '').length,
  },
}];

const inputData = $input.first().json || {};
