const inputData = $input.first().json || {};
const promptData = $('Build Humanizer Prompt').first().json || {};

const rawHumanized = String(inputData.output || inputData.text || inputData.response || '').trim();
const fallbackComment = String(promptData.comment || '').trim();

function looksTemplate(text) {
  const t = String(text || '').trim();
  if (!t) return true;
  if (t.length < 160) return true;
  return /(without the specific input text|please provide the text|provide text|предоставьте|шаблонный ответ|шаблонный текст|введите текст)/i.test(t);
}

let comment = rawHumanized;
let usedFallbackComment = false;
if (looksTemplate(rawHumanized) && fallbackComment.length > 300) {
  comment = fallbackComment;
  usedFallbackComment = true;
}

const targetLength = String(promptData.targetLength || '1500-2000');
const targetMin = parseInt(targetLength.split('-')[0], 10) || 1200;
const targetMax = parseInt(targetLength.split('-')[1] || targetLength.split('-')[0], 10) || 2200;

const warnings = [];
const critical = [];

const charCount = comment.length;
if (charCount < Math.floor(targetMin * 0.85)) {
  const msg = `Слишком коротко: ${charCount} символов (минимум ~${targetMin})`;
  warnings.push(msg);
  critical.push(msg);
}
if (charCount > Math.ceil(targetMax * 1.15)) {
  const msg = `Слишком длинно: ${charCount} символов (максимум ~${targetMax})`;
  warnings.push(msg);
  critical.push(msg);
}

// Cyrillic character detection — proportional floor (v2.1: supports short comments)
const cyrillicCount = (comment.match(/[а-яА-ЯёЁ]/g) || []).length;
const cyrillicMin = Math.max(50, Math.floor(targetMin * 0.15));
if (cyrillicCount < cyrillicMin) {
  const msg = `Недостаточно кириллицы в тексте (${cyrillicCount} < ${cyrillicMin})`;
  warnings.push(msg);
  critical.push(msg);
}

if (/(without the specific input text|please provide the text|provide text|предоставьте|шаблонный ответ|шаблонный текст|\[([A-Z_]+)\]|\{\{[^}]+\}\})/i.test(comment)) {
  const msg = 'Обнаружены шаблонные фразы/маркеры';
  warnings.push(msg);
  critical.push(msg);
}

const question = String(promptData.question || '').toLowerCase();
const questionWords = question.split(/\s+/).filter((w) => w.length > 4);
const loweredComment = comment.toLowerCase();
const matched = questionWords.filter((w) => loweredComment.includes(w));
const questionRelevance = questionWords.length === 0 ? true : matched.length > 0;
if (!questionRelevance) {
  const msg = 'Комментарий не отвечает на вопрос пользователя';
  warnings.push(msg);
  critical.push(msg);
}

const passed = critical.length === 0;

return [{
  json: {
    ...promptData,
    comment,
    charCount,
    passed,
    warnings,
    criticalWarnings: critical,
    questionRelevance,
    retryUsed: Boolean(promptData.retryUsed),
    hasGuillemets: /[«»]/.test(comment),
    hasEmDash: /—/.test(comment),
    usedFallbackComment,
    rawHumanized,
  },
}];

