const data = $input.first().json || {};
const comment = String(data.comment || '').trim();
const reasons = [];

if (!data.passed) {
  reasons.push(...(data.criticalWarnings || data.warnings || []));
}

const targetLength = String(data.targetLength || '1200-1800');
const targetMin = parseInt(targetLength.split('-')[0]) || 1200;
const targetMax = parseInt(targetLength.split('-')[1]) || 1800;
const tolerance = 0.15;
const minLen = Math.floor(targetMin * (1 - tolerance));
const maxLen = Math.ceil(targetMax * (1 + tolerance));

const charCount = comment.length;
if (charCount < minLen) {
  reasons.push(`Слишком коротко: ${charCount} символов (мин. ${minLen})`);
}
if (charCount > maxLen) {
  reasons.push(`Слишком длинно: ${charCount} символов (макс. ${maxLen})`);
}

const cyrillicCount = (comment.match(/[а-яёА-ЯЁ]/g) || []).length;
if (cyrillicCount < 100) {
  reasons.push(`Мало кириллицы: ${cyrillicCount} символов`);
}

const emojiMatch = comment.match(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}]/gu) || [];
if (emojiMatch.length > 0) {
  reasons.push(`Найдены эмодзи: ${emojiMatch.length} шт`);
}

const passed = reasons.length === 0;

return [{
  json: {
    ...data,
    passed,
    qualityPassed: passed,
    qualityReasons: reasons,
    charCount
  }
}];

