function parseProfile(payload) {
  if (!payload || typeof payload !== 'object') return null;
  if (payload.profile_id) return payload;
  if (typeof payload.content === 'string') {
    try {
      const decoded = Buffer.from(payload.content, 'base64').toString('utf8');
      return JSON.parse(decoded);
    } catch (_) {
      return null;
    }
  }
  return null;
}

const base = $('Parse Profile').first().json;
const fallbackRaw = $input.first().json || {};
const parsedFallback = parseProfile(fallbackRaw);
const fallbackValid = Boolean(parsedFallback && parsedFallback.active === true);

const requestedProfile = fallbackValid ? parsedFallback : (base.requestedProfile || null);
const requestedProfileValid = Boolean(fallbackValid || base.requestedProfileValid);

return [{
  json: {
    ...base,
    requestedProfile,
    requestedProfileValid,
    profileResolutionHint: requestedProfileValid ? 'requested_active' : 'fallback_default',
    profileFetchError: requestedProfileValid ? null : (base.profileFetchError || fallbackRaw.error || null),
    fallbackFetchError: fallbackRaw.error || null,
  },
}];

